import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSDemoServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Safe code: Sanitized user input is embedded into the HTML response
        String htmlResponse = "<html><body><h1>Welcome " + sanitizedUserInput + "!</h1></body></html>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
